- (NSString *)chartPackRoot { NSFileManager *fm=[NSFileManager defaultManager];NSString *root=@"/var/mobile/Library/SkyCharts/ChartPacks",*legacy=@"/var/mobile/Library/AtlasSix/ChartPacks";[fm createDirectoryAtPath:root withIntermediateDirectories:YES attributes:nil error:NULL];for(NSString *directory in [fm contentsOfDirectoryAtPath:legacy error:NULL]){NSString *source=[legacy stringByAppendingPathComponent:directory],*target=[root stringByAppendingPathComponent:directory];if(![fm fileExistsAtPath:target])[fm moveItemAtPath:source toPath:target error:NULL];}return root; }
