- (void)rebuildChartGroups { if(self.selectedCategoryIndex<0||self.selectedCategoryIndex>=self.categories.count){self.chartGroups=[NSArray array];return;}NSArray *charts=[[self.categories objectAtIndex:self.selectedCategoryIndex]objectForKey:@"charts"]?:[NSArray array];NSMutableDictionary *byRunway=[NSMutableDictionary dictionary];for(NSDictionary *chart in charts){NSArray *runways=[chart objectForKey:@"runways"];if(!runways.count)runways=[NSArray arrayWithObject:@"GENERAL"];for(NSString *runwayValue in runways){NSString *runway=[[runwayValue description]stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];if(!runway.length)runway=@"GENERAL";NSString *key=[runway isEqualToString:@"GENERAL"]?@"GENERAL":[@"RWY " stringByAppendingString:[runway uppercaseString]];NSMutableArray *items=[byRunway objectForKey:key];if(!items){items=[NSMutableArray array];[byRunway setObject:items forKey:key];}if(![items containsObject:chart])[items addObject:chart];}}NSMutableArray *keys=[NSMutableArray arrayWithArray:[byRunway allKeys]];[keys sortUsingComparator:^NSComparisonResult(NSString *left,NSString *right){if([left isEqualToString:@"GENERAL"])return NSOrderedAscending;if([right isEqualToString:@"GENERAL"])return NSOrderedDescending;return [left compare:right options:NSNumericSearch];}];NSMutableArray *groups=[NSMutableArray array];for(NSString *key in keys)[groups addObject:[NSDictionary dictionaryWithObjectsAndKeys:key,@"name",[byRunway objectForKey:key],@"charts",nil]];self.chartGroups=groups; }
