- (void)transitionChartListVisible:(BOOL)shown {
    CGSize size=self.view.bounds.size;CGFloat top=58,footer=34,rail=size.width<800?66:78,list=MIN(300,MAX(240,size.width*.34)),contentHeight=size.height-top-footer;
    CGFloat viewerX=rail+(shown?list:0),viewerWidth=size.width-rail-(shown?list:0);
    self.chartListVisible=shown;self.chartTable.hidden=NO;self.chartTable.frame=CGRectMake(shown?rail-list:rail,top,list,contentHeight);
    [self.view bringSubviewToFront:self.categoryRail];[self.view bringSubviewToFront:self.categoryTable];[self.view bringSubviewToFront:self.topBar];[self.view bringSubviewToFront:self.footer];
    self.chartTable.alpha=shown?0:1;
    [UIView beginAnimations:@"SkyChartsChartList" context:NULL];[UIView setAnimationDuration:.28];[UIView setAnimationCurve:UIViewAnimationCurveEaseInOut];[UIView setAnimationBeginsFromCurrentState:YES];[UIView setAnimationDelegate:self];[UIView setAnimationDidStopSelector:@selector(chartListTransitionDidStop:finished:context:)];
    self.chartTable.alpha=shown?1:0;self.chartTable.frame=CGRectMake(shown?rail:rail-list,top,list,contentHeight);self.scrollView.frame=CGRectMake(viewerX,top,viewerWidth,contentHeight);[UIView commitAnimations];
}
