- (void)tableView:(UITableView *)table didSelectRowAtIndexPath:(NSIndexPath *)path {
    if(table==self.categoryTable){
        BOOL shouldShow=!(path.row==self.selectedCategoryIndex&&self.chartListVisible),visibilityChanged=shouldShow!=self.chartListVisible;
        if(path.row!=self.selectedCategoryIndex){self.selectedCategoryIndex=path.row;self.selectedChart=nil;[self rebuildChartGroups];}
