        if(visibilityChanged)[self transitionChartListVisible:shouldShow];else if(self.imageView.image)[self fitChart];
    }else{self.selectedChart=[[[self.chartGroups objectAtIndex:path.section]objectForKey:@"charts"]objectAtIndex:path.row];self.chartPages=[self.selectedChart objectForKey:@"pages"]?:[NSArray array];self.pageIndex=0;[self.chartTable reloadData];[self loadCurrentImage];}
}

- (void)loadCurrentImage { if(!self.chartPages.count)return;NSDictionary *page=[self.chartPages objectAtIndex:self.pageIndex];NSString *relative=[page objectForKey:@"light"];NSString *path=[[self.selectedAirport objectForKey:@"packPath"]stringByAppendingPathComponent:relative];[self performSelectorInBackground:@selector(loadImageBackground:)withObject:path];self.statusLabel.text=@"Loading offline chart…"; }
- (void)loadImageBackground:(NSString *)path { NSAutoreleasePool *pool=[[NSAutoreleasePool alloc]init];UIImage *image=[UIImage imageWithContentsOfFile:path];[self performSelectorOnMainThread:@selector(imageFinished:)withObject:image waitUntilDone:NO];[pool drain]; }
