- (UIView *)viewForZoomingInScrollView:(UIScrollView *)scroll { return self.imageView; }
- (void)centerChart { CGSize bounds=self.scrollView.bounds.size,content=self.scrollView.contentSize;self.scrollView.contentInset=UIEdgeInsetsZero;self.imageView.center=CGPointMake(MAX(content.width,bounds.width)/2,MAX(content.height,bounds.height)/2); }
- (void)scrollViewDidZoom:(UIScrollView *)scrollView { if(scrollView==self.scrollView)[self centerChart]; }
