- (void)previousPage { if(self.pageIndex>0){self.pageIndex--;[self loadCurrentImage];} }
- (void)nextPage { if(self.pageIndex+1<self.chartPages.count){self.pageIndex++;[self loadCurrentImage];} }

- (void)showWeather { NSString *icao=[self.selectedAirport objectForKey:@"ident"];if(!icao.length){UIAlertView *alert=[[[UIAlertView alloc]initWithTitle:@"Weather" message:@"Select an installed airport before requesting METAR weather." delegate:nil cancelButtonTitle:@"OK" otherButtonTitles:nil]autorelease];[alert show];return;}WeatherViewController *weather=[[[WeatherViewController alloc]initWithICAO:icao]autorelease];UINavigationController *nav=[[[UINavigationController alloc]initWithRootViewController:weather]autorelease];nav.modalPresentationStyle=UIModalPresentationFormSheet;[self presentModalViewController:nav animated:YES]; }
- (NSString *)airportMapRoot { NSString *root=@"/var/mobile/Library/SkyCharts/AirportMaps";[[NSFileManager defaultManager]createDirectoryAtPath:root withIntermediateDirectories:YES attributes:nil error:NULL];return root; }
- (NSString *)airportMapPathForICAO:(NSString *)icao { return [[self airportMapRoot]stringByAppendingPathComponent:[NSString stringWithFormat:@"%@.json",[icao uppercaseString]]]; }
- (NSString *)installedAirportMapPath { NSString *relative=[self.selectedAirport objectForKey:@"map"],*packPath=[self.selectedAirport objectForKey:@"packPath"];if(relative.length&&packPath.length&&![relative hasPrefix:@"/"]&&[relative rangeOfString:@".."].location==NSNotFound){NSString *bundled=[packPath stringByAppendingPathComponent:relative];if([[NSFileManager defaultManager]fileExistsAtPath:bundled])return bundled;}NSString *icao=[self.selectedAirport objectForKey:@"ident"],*legacy=[self airportMapPathForICAO:icao];return [[NSFileManager defaultManager]fileExistsAtPath:legacy]?legacy:nil; }
- (void)openAirportMap { NSString *icao=[self.selectedAirport objectForKey:@"ident"];if(!icao.length){UIAlertView *alert=[[[UIAlertView alloc]initWithTitle:@"Airport Map" message:@"Select an installed airport before opening its map." delegate:nil cancelButtonTitle:@"OK" otherButtonTitles:nil]autorelease];[alert show];return;}NSString *path=[self installedAirportMapPath];if(!path){UIAlertView *alert=[[[UIAlertView alloc]initWithTitle:[NSString stringWithFormat:@"%@ Airport Map",icao]message:@"This chart package does not contain an interactive airport map. Re-download the airport while the Mac Pack Agent is running."delegate:nil cancelButtonTitle:@"OK"otherButtonTitles:nil]autorelease];[alert show];return;}AirportMapViewController *map=[[[AirportMapViewController alloc]initWithICAO:icao mapPath:path]autorelease];UINavigationController *nav=[[[UINavigationController alloc]initWithRootViewController:map]autorelease];nav.modalPresentationStyle=UIModalPresentationFullScreen;[self presentModalViewController:nav animated:YES]; }
- (NSString *)agentBase { return [[NSUserDefaults standardUserDefaults]stringForKey:@"packAgentURL"]?:@"http://192.168.2.2:8770"; }
- (void)openPackMenu { UIActionSheet *sheet=[[[UIActionSheet alloc]initWithTitle:@"Settings" delegate:self cancelButtonTitle:@"Cancel" destructiveButtonTitle:nil otherButtonTitles:@"Download by Country",@"Download by ICAO Code",@"Manage Downloaded Content",@"About SkyCharts",nil]autorelease];[sheet showInView:self.view]; }
- (void)actionSheet:(UIActionSheet *)sheet clickedButtonAtIndex:(NSInteger)index { if(index==0)[self showAgentPromptForMode:101];else if(index==1)[self showAgentPromptForMode:102];else if(index==2){ContentManagerViewController *manager=[[[ContentManagerViewController alloc]init]autorelease];UINavigationController *nav=[[[UINavigationController alloc]initWithRootViewController:manager]autorelease];nav.modalPresentationStyle=UIModalPresentationFormSheet;[self presentModalViewController:nav animated:YES];}else if(index==3){AboutViewController *about=[[[AboutViewController alloc]init]autorelease];UINavigationController *nav=[[[UINavigationController alloc]initWithRootViewController:about]autorelease];nav.modalPresentationStyle=UIModalPresentationFormSheet;[self presentModalViewController:nav animated:YES];} }
- (void)showAgentPromptForMode:(NSInteger)mode { UIAlertView *alert=[[[UIAlertView alloc]initWithTitle:@"Mac Pack Agent" message:@"Enter the Mac agent address" delegate:self cancelButtonTitle:@"Cancel" otherButtonTitles:@"Next",nil]autorelease];alert.tag=mode==101?110:120;alert.alertViewStyle=UIAlertViewStylePlainTextInput;[alert textFieldAtIndex:0].text=[self agentBase];[alert show]; }
- (void)showCountryPrompt { UIAlertView *alert=[[[UIAlertView alloc]initWithTitle:@"Download Country" message:@"Two-letter code, e.g. CA. Use CA:10 for a trial." delegate:self cancelButtonTitle:@"Cancel" otherButtonTitles:@"Download",nil]autorelease];alert.tag=101;alert.alertViewStyle=UIAlertViewStylePlainTextInput;[alert show]; }
- (void)showICAOPackPrompt { UIAlertView *alert=[[[UIAlertView alloc]initWithTitle:@"Download Airports" message:@"Enter ICAO codes separated by commas" delegate:self cancelButtonTitle:@"Cancel" otherButtonTitles:@"Download",nil]autorelease];alert.tag=102;alert.alertViewStyle=UIAlertViewStylePlainTextInput;[alert show]; }
- (void)alertView:(UIAlertView *)alert clickedButtonAtIndex:(NSInteger)index { if(index!=1)return;if(alert.tag==110||alert.tag==120){NSString *url=[[alert textFieldAtIndex:0].text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];while([url hasSuffix:@"/"])url=[url substringToIndex:url.length-1];[[NSUserDefaults standardUserDefaults]setObject:url forKey:@"packAgentURL"];if(alert.tag==110)[self showCountryPrompt];else[self showICAOPackPrompt];}else if(alert.tag==101)[self startPackJob:[[[alert textFieldAtIndex:0].text uppercaseString]stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]]];else if(alert.tag==102)[self startAirportPackJob:[[[alert textFieldAtIndex:0].text uppercaseString]stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]]];else if(alert.tag==200)[self selectAirportByCode:[alert textFieldAtIndex:0].text]; }
